import{c as e,Q as n,j as r,m as a}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Context Engineering: Filling the window with just the right information — @karpathy","description":"","frontmatter":{"title":"Context Engineering: Filling the window with just the right information — @karpathy","author":"Andrej Karpathy（@karpathy）","date":"2026-05-01T00:00:00.000Z","source":"https://x.com/karpathy/status/1937902205765607626","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-01-@karpathy-context-engineering-shift.md","filePath":"research/tweets/2026-05-01-@karpathy-context-engineering-shift.md","lastUpdated":1779894392000}'),o={name:"research/tweets/2026-05-01-@karpathy-context-engineering-shift.md"};function i(s,t,h,g,c,d){return n(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="context-engineering-filling-the-window-with-just-the-right-information-—-karpathy" tabindex="-1">Context Engineering: Filling the window with just the right information — @karpathy <a class="header-anchor" href="#context-engineering-filling-the-window-with-just-the-right-information-—-karpathy" aria-label="Permalink to &quot;Context Engineering: Filling the window with just the right information — @karpathy&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/karpathy/status/1937902205765607626" target="_blank" rel="noreferrer">https://x.com/karpathy/status/1937902205765607626</a><strong>作者</strong>：Andrej Karpathy（@karpathy） <strong>發布日期</strong>：2026-05-01（近似） <strong>收錄日期</strong>：2026-05-10 <strong>類型</strong>：推文（+ 後續討論） <strong>分類</strong>：context-engineering</p><hr><h2 id="核心推文" tabindex="-1">核心推文 <a class="header-anchor" href="#核心推文" aria-label="Permalink to &quot;核心推文&quot;">​</a></h2><blockquote><p>&quot;I suggest to use the term &#39;context engineering&#39; over &#39;prompt engineering&#39;. It is more accurate to the actual challenge:</p><p>— filling the context window with just the right information for the next step — it&#39;s not just about wording a single prompt — it&#39;s about system design: memory, tool outputs, search results, instructions, etc.</p><p>Prompt engineering = write a better sentence. Context engineering = system architecture.&quot;</p></blockquote><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：Karpathy 正式確立「context engineering」術語，將關注點從「提示措辭」移向「系統設計」——memory、tool outputs、search results、instructions 的架構配置。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>Prompt Engineering 的侷限性</strong>：prompt 只是一句話，context engineering 是系統架構決策</li><li><strong>Context Window as Resource</strong>：填充的「不是更多資訊」，而是「下一步恰好所需的資訊」</li><li><strong>Harness 與 Context 的連結</strong>：harness 決定了哪些資訊進入 context → harness IS context engineering</li></ol><h3 id="關鍵引用" tabindex="-1">關鍵引用 <a class="header-anchor" href="#關鍵引用" aria-label="Permalink to &quot;關鍵引用&quot;">​</a></h3><blockquote><p>&quot;The delicate science of filling the context window with just the right information for the next step.&quot; — @karpathy</p></blockquote><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>相關性</td><td>10/10</td><td>直接定義 cc-workspace 的核心實踐框架</td></tr><tr><td>可行動性</td><td>9/10</td><td>重新框架了所有 harness 設計決策</td></tr><tr><td>新穎性</td><td>8/10</td><td>術語統一有重大影響，論點本身不全新</td></tr><tr><td><strong>總評</strong></td><td><strong>9/10</strong></td><td>—</td></tr></tbody></table><hr><h2 id="與-cc-workspace-的連結" tabindex="-1">與 cc-workspace 的連結 <a class="header-anchor" href="#與-cc-workspace-的連結" aria-label="Permalink to &quot;與 cc-workspace 的連結&quot;">​</a></h2><ul><li><code>context-management.md</code> §理論錨點直接引用此推文（已收錄）</li><li>支持 CLAUDE.md 的三層載入策略（auto → on-demand → manual = context engineering）</li><li>強化 harness-design.md 的設計哲學：harness 工程 = context 工程</li></ul><p><strong>已在 workspace 中引用</strong>：<code>research/tweets/2025-06-25-@karpathy-607626.md</code>（原始推文版本，此為 2026-05 後續討論擴散版）</p>',19)])])}const u=e(o,[["render",i]]);export{p as __pageData,u as default};
